require"UI.UIBase"require"UI.UIBlock"UI_GiftCode=UIBase:Inherit()function UI_GiftCode:OnCreate()UI_GiftCode.Inst=self;self.btn_cd=0;self.codemap={}self:InitMap()self.input=self.root.transform:Find('InputField'):GetComponent(typeof(UnityEngine.UI.InputField))self.btn_confirm.transform.gameObject:SetActive(true)self.btn_confirm.onClick:AddListener(function()self:Confirm()end)self.input.onValueChanged:RemoveAllListeners()self.input.onValueChanged:AddListener(function(a)local b=a:gsub("[%s\n]","")self.input.text=b end)end;function UI_GiftCode:OnShow(c)if self.locking then return end;self.locking=true;self:AnimPopOut(self.root,function()self.locking=false;c()end)self.transform.gameObject:SetActive(true)ControllerMgr.RegistBtnBack(self.btn_close)end;function UI_GiftCode:OnClose(c)if self.locking then return end;self.locking=true;self:AnimPopHide(self.root,function()self.locking=false end)self.transform.gameObject:SetActive(false)self.input.text=''c()end;function UI_GiftCode:Confirm()if self.locking then return end;if self.btn_cd>Tools.GetRealTime()then return end;self.btn_cd=Tools.GetRealTime()+1;if self:IsSpecial(self.input.text)then local d=ProtoMgr.CreateRequest('Lobby','useSpecialGiftCode')d.code=self.input.text;LobbyNetMgr.SendRequest('Lobby','useSpecialGiftCode',d,function(e,f)self.btn_cd=0;if e or f.error and f.error.code~=0 then UIMgr.Inst:ShowUI(UI_ErrorInfo.className,nil,{errorType=UI_ErrorInfo.ErrorType.NetWork,method='useSpecialGiftCode',error=e,res=f})else if f.rewards and#f.rewards~=0 then local g=Tools.HandleExecuteReward(f.rewards)Tools.ShowRewards({rewards=g})end end end)else local d=ProtoMgr.CreateRequest('Lobby','useGiftCode')d.code=self.input.text;LobbyNetMgr.SendRequest('Lobby','useGiftCode',d,function(e,f)self.btn_cd=0;if e or f.error and f.error.code~=0 then UIMgr.Inst:ShowUI(UI_ErrorInfo.className,nil,{errorType=UI_ErrorInfo.ErrorType.NetWork,method='useGiftCode',error=e,res=f})else Tools.ShowRewards(f)end end)end end;function UI_GiftCode:InitMap()local h={'A','B','C','D','E','F','G','H','J','K','M','N','P','Q','R','S','T','U','V','W','X','Y','Z','2','3','4','5','6','7','8','9'}for i=1,#h do self.codemap[h[i]]=1 end end;function UI_GiftCode:IsSpecial(j)if Tools.GetStringLength(j)~=12 then return true end;for i=1,12 do local k=Tools.UTF8Sub(j,i,1)if not self.codemap[k]then return true end end;return false end;return UI_GiftCode